/// Acoustic Manifold representing a Takens' Delay Embedding of audio data.
#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct AcousticManifold {
    pub points: Vec<f32>,
    pub delay: usize,
    pub embedding_dim: usize,
}

/// Persistence Barcode capturing the topological features of the acoustic cloud.
#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct PersistenceBarcode {
    pub beta1: u32,
    pub lifespan: u32,
    pub dilation: f32,
    pub density: f32,
}

impl PersistenceBarcode {
    /// Projects the discrete barcode into a Moonshine Vector.
    pub fn to_moonshine(&self, node_id: String) -> MoonshineVector {
        let boundary_trace = (self.beta1 * 1000) + self.lifespan;

        MoonshineVector {
            node_id,
            bulk_state: vec![self.dilation, self.density],
            boundary_trace,
            dimension: GRIESS_DIMENSION,
        }
    }
}

/// A Shadow Debt represents unresolved emotional tension (the Topological Remainder).
#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct ShadowDebt {
    pub original_debt: TopologicalDebt,
    pub remainder_volume: f32,
    pub emotional_gravity: f32,
}

/// The Phoneme Reservoir stores detached acoustic geometries (phonemes, prosody).
/// These "breathe" in the L1 RAM, waiting for a semantic debt to pull them.
pub struct PhonemeReservoir {
    pub phonemes: HashMap<String, MoonshineVector>,
}

impl PhonemeReservoir {
    pub fn new() -> Self {
        Self {
            phonemes: HashMap::new(),
        }
    }

    pub fn add_phoneme(&mut self, id: &str, vector: MoonshineVector) {
        self.phonemes.insert(id.to_string(), vector);
    }

    /// 'Steals' phonemes from a MOSS-style RVQ codebook.
    /// In a real system, this would parse the RVQ tensors from a .knot file.
    pub fn steal_from_moss(&mut self, rvq_codebook: &[f32], code_dim: usize) {
        let num_codes = rvq_codebook.len() / code_dim;
        for i in 0..num_codes {
            let start = i * code_dim;
            let end = start + code_dim;
            let code = &rvq_codebook[start..end];

            // Map the RVQ code into the Griess Algebra
            let id = format!("moss_rvq_{}", i);
            let vector = MoonshineVector {
                node_id: id.clone(),
                bulk_state: code.to_vec(),
                boundary_trace: (i as u32 % 1000) + 1, // Deterministic topological anchor
                dimension: GRIESS_DIMENSION,
            };
            self.phonemes.insert(id, vector);
        }
    }
}

impl Default for PhonemeReservoir {
    fn default() -> Self {
        Self::new()
    }
}

/// The Zigzag Orchestrator handles continuous audio streams without Time.
pub struct ZigzagOrchestrator {
    pub comet_tail: Vec<CometPoint>,
    pub cooling_rate: f32,
}

impl ZigzagOrchestrator {
    pub fn new(cooling_rate: f32) -> Self {
        Self {
            comet_tail: Vec::new(),
            cooling_rate,
        }
    }

    /// Inhales a chunk of audio and exhales the resulting topological barcode.
    pub fn inhale(&mut self, audio_chunk: &[f32]) -> (u32, f32, f32) {
        let new_points = math::takens_embedding(audio_chunk, 2, 3);
        math::zigzag_step(&mut self.comet_tail, new_points, self.cooling_rate);
        math::compute_comet_barcode(&self.comet_tail)
    }

    /// Topological Packing: Merges a second concurrent audio manifold into the active super-manifold.
    /// This allows the system to process multiple 'layers' of audio simultaneously.
    pub fn pack_manifold(&mut self, secondary_audio: &[f32]) {
        let secondary_points = math::takens_embedding(secondary_audio, 2, 3);
        // Inject points from a secondary source into the same Amplituhedron
        math::zigzag_step(&mut self.comet_tail, secondary_points, self.cooling_rate);
    }
}

